data = [
  {"id":  1, "name": "乾",   "六十四卦": "乾為天",   "卦辭": "元，亨，利，貞。",                                                           "爻辭": {"初九": "潛龍，勿用。",                                           "九二": "見龍在田，利見大人。", "九三": "君子終日乾乾，夕惕若，厲，無咎。", "九四": "或躍在淵，無咎。", "九五": "飛龍在天，利見大人。", "上九": "亢龍有悔。", "用九": "見群龍無首，吉。"}},
  {"id":  2, "name": "坤",   "六十四卦": "坤為地",   "卦辭": "元，亨，利牝馬之貞.君子有攸往，先迷後得主，利。西南得朋，東北喪朋。安貞，吉。",   "爻辭": {"初六": "履霜，堅冰至。",                                         "六二": "直，方，大，不習，無不利。", "六三": "含章可貞，或從王事，無成有終。", "六四": "括囊，無咎無譽。", "六五": "黃裳，元吉。", "上六": "龍戰于野，其血玄黃。", "用六": "利永貞。"}},
  {"id":  3, "name": "屯",   "六十四卦": "水雷屯",   "卦辭": "元，亨，利，貞。勿用，有攸往，利建侯。",                                       "爻辭": {"初九": "磐桓，利居貞，利建侯。",                                 "六二": "屯如，邅如，乘馬班如.匪寇婚媾，女子貞不字，十年乃字。", "六三": "即鹿無虞，惟入于林中.君子幾不如舍，往吝。", "六四": "乘馬班如，求婚媾，往吉，無不利。", "九五": "屯其膏，小貞吉，大貞凶。", "上六": "乘馬班如，泣血漣如。"}},
  {"id":  4, "name": "蒙",   "六十四卦": "山水蒙",   "卦辭": "亨。匪我求童蒙，童蒙求我.初筮告，再三瀆，瀆則不告。利貞。",                      "爻辭": {"初六": "發蒙，利用刑人，用說桎梏，以往吝。",                      "九二": "包蒙吉，納婦吉，子克家。", "六三": "勿用取女，見金夫，不有躬，無攸利。", "六四": "困蒙，吝。", "六五": "童蒙，吉。", "上九": "擊蒙，不利為寇，利禦寇。"}},
  {"id":  5, "name": "需",   "六十四卦": "水天需",   "卦辭": "有孚，光亨，貞吉.利涉大川。",                                                 "爻辭": {"初九": "需于郊，利用恆，無咎。",                                 "九二": "需于沙，小有言，終吉。", "九三": "需于泥，致寇至。", "六四": "需于血，出自穴。", "九五": "需于酒食，貞吉。", "上六": "入于穴，有不速之客三人來，敬之終吉。"}},
  {"id":  6, "name": "訟",   "六十四卦": "天水訟",   "卦辭": "有孚，窒，惕中吉，終凶.利見大人，不利涉大川。",                                 "爻辭": {"初六": "不永所事，小有言，終吉。",                               "九二": "不克訟，歸而逋，其邑人三百戶，無眚。", "六三": "食舊德，貞厲，終吉.或從王事，無成。", "九四": "不克訟，復即命，渝安貞，吉。", "九五": "訟，元吉。", "上九": "或錫之鞶帶，終朝三褫之。"}},
  {"id":  7, "name": "師",   "六十四卦": "地水师",   "卦辭": "貞，丈人，吉，無咎。",                                                        "爻辭": {"初六": "師出以律，否臧凶。",                                    "九二": "在師中，吉，無咎，王三錫命。", "六三": "師或輿尸，凶。", "六四": "師左次，無咎。", "六五": "田有禽，利執言，無咎.長子帥師，弟子輿尸，貞凶。", "上六": "大君有命，開國承家，小人勿用。"}},
  {"id":  8, "name": "比",   "六十四卦": "水地比",   "卦辭": "吉.原筮，元永貞，無咎.不寧方來，後夫凶。",                                      "爻辭": {"初六": "有孚比之，無咎.有孚盈缶，終來有他，吉。",                 "六二": "比之自內，貞吉。", "六三": "比之匪人。", "六四": "外比之，貞吉。", "九五": "顯比，王用三驅，失前禽.邑人不誡，吉。", "上六": "比之無首，凶。"}},
  {"id":  9, "name": "小畜", "六十四卦": "風天小畜", "卦辭": "亨.密雲不雨，自我西郊。",                                                      "爻辭": {"初九": "復自道，何其咎，吉。",                                  "九二": "牽復，吉。", "九三": "輿說輻，夫妻反目。", "六四": "有孚，血去惕出，無咎。", "九五": "有孚攣如，富以其鄰。", "上九": "既雨既處，尚德載，婦貞厲，月幾望，君子征凶。"}},
  {"id": 10, "name": "履",   "六十四卦": "天澤履",   "卦辭": "履虎尾，不咥人，亨。",                                                        "爻辭": {"初九": "素履之往，無咎。",                                      "九二": "履道坦坦，幽人貞吉。", "六三": "眇能視，跛能履.履虎尾，咥人，凶.武人為于大君。", "九四": "履虎尾，愬愬，終吉。", "九五": "夬履，貞厲。", "上九": "視履考祥，其旋元吉。"}},
  {"id": 11, "name": "泰",   "六十四卦": "地天泰",   "卦辭": "小往大來，吉亨。",                                                            "爻辭": {"初九": "拔茅茹，以其彙，征吉。",                                "九二": "包荒，用馮河，不遐遺，朋亡，得尚于中行。", "九三": "無平不陂，無往不復.艱貞無咎，勿恤其孚，于食有福。", "六四": "翩翩，不富以其鄰，不戒以孚。", "六五": "帝乙歸妹，以祉元吉。", "上六": "城復于隍，勿用師，自邑告命，貞吝。"}},
  {"id": 12, "name": "否",   "六十四卦": "天地否",   "卦辭": "否之匪人，不利君子貞，大往小來。",                                             "爻辭": {"初六": "拔茅茹，以其彙，貞吉亨。",                               "六二": "包承，大人否亨，小人吉。", "六三": "包羞。", "九四": "有命，無咎，疇離祉。", "九五": "休否，大人吉.其亡其亡，繫于苞桑。", "上九": "傾否，先否後喜。"}},
  {"id": 13, "name": "同人", "六十四卦": "天火同人", "卦辭": "同人于野，亨.利涉大川，利君子貞。",                                             "爻辭": {"初九": "同人于門，無咎。",                                     "六二": "同人于宗，吝。", "九三": "伏戎于莽，升其高陵，三歲不興。", "九四": "乘其墉，弗克攻，吉。", "九五": "同人，先號啕而後笑，大師克相遇。", "上九": "同人于郊，無悔。"}},
  {"id": 14, "name": "大有", "六十四卦": "火天大有", "卦辭": "元亨。",                                                                     "爻辭": {"初九": "無交害，無咎，艱則無咎。",                               "九二": "大車以載，有攸往，無咎。", "九三": "公用亨于天子，小人弗克。", "九四": "匪其彭，無咎。", "六五": "厥孚交如，威如，吉。", "上九": "自天祐之，吉無不利。"}},
  {"id": 15, "name": "謙",   "六十四卦": "地山谦",   "卦辭": "亨.君子有終。",                                                              "爻辭": {"初六": "謙謙君子，用涉大川，吉。",                               "六二": "鳴謙，貞吉。", "九三": "勞謙君子，有終吉。", "六四": "無不利，撝謙。", "六五": "不富以其鄰，利用侵伐，無不利。", "上六": "鳴謙，利用行師，征邑國。"}},
  {"id": 16, "name": "豫",   "六十四卦": "雷地豫",   "卦辭": "利建侯，行師。",                                                              "爻辭": {"初六": "鳴豫，凶。",                                           "六二": "介于石，不終日，貞吉。", "六三": "盱豫，悔，遲有悔。", "九四": "由豫，大有得，勿疑，朋盍簪。", "六五": "貞疾，恆不死。", "上六": "冥豫，成有渝，無咎。"}},
  {"id": 17, "name": "隨",   "六十四卦": "澤雷隨",   "卦辭": "元，亨，利，貞，無咎。",                                                      "爻辭": {"初九": "官有渝，貞吉.出門交有功。",                              "六二": "係小子，失丈夫。", "六三": "係丈夫，失小子.隨有求得，利居貞。", "九四": "隨有獲，貞凶.有孚在道，以明，何咎。", "九五": "孚于嘉，吉。", "上六": "拘係之，乃從維之.王用亨于西山。"}},
  {"id": 18, "name": "蠱",   "六十四卦": "山風蠱",   "卦辭": "元亨，利涉大川.先甲三日，後甲三日。",                                          "爻辭": {"初六": "幹父之蠱，有子考無咎，厲終吉。",                         "九二": "幹母之蠱，不可貞。", "九三": "幹父之蠱，小有悔，無大咎。", "六四": "裕父之蠱，往見吝。", "六五": "幹父之蠱，用譽。", "上九": "不事王侯，高尚其事。"}},
  {"id": 19, "name": "臨",   "六十四卦": "地澤臨",   "卦辭": "元，亨，利，貞.至于八月有凶。",                                               "爻辭": {"初九": "咸臨，貞吉。",                                          "九二": "咸臨，吉無不利。", "六三": "甘臨，無攸利.既憂之，無咎。", "六四": "至臨，無咎。", "六五": "知臨，大君之宜，吉。", "上六": "敦臨，吉無咎。"}},
  {"id": 20, "name": "觀",   "六十四卦": "風地觀",   "卦辭": "盥而不薦，有孚顒若。",                                                        "爻辭": {"初六": "童觀，小人無咎，君子吝。",                              "六二": "窺觀，利女貞。", "六三": "觀我生，進退。", "六四": "觀國之光，利用賓于王。", "九五": "觀我生，君子無咎。", "上九": "觀其生，君子無咎。"}},
  {"id": 21, "name": "噬嗑", "六十四卦": "火雷噬嗑", "卦辭": "亨，利用獄。",                                                               "爻辭": {"初九": "履校滅趾，無咎。",                                      "六二": "噬膚滅鼻，無咎。", "六三": "噬臘肉，遇毒，小吝，無咎。", "九四": "噬乾胏，得金矢，利艱貞，吉。", "六五": "噬乾肉，得黃金，貞厲，無咎。", "上九": "何校滅耳，凶。"}},
  {"id": 22, "name": "賁",   "六十四卦": "山火賁",   "卦辭": "亨.小利有攸往。",                                                            "爻辭": {"初九": "賁其趾，舍車而徒。",                                    "六二": "賁其須。", "九三": "賁如濡如，永貞吉。", "六四": "賁如皤如，白馬翰如，匪寇婚媾。", "六五": "賁于丘園，束帛戔戔，吝終吉。", "上九": "白賁，無咎。"}},
  {"id": 23, "name": "剝",   "六十四卦": "山地剝",   "卦辭": "不利有攸往。",                                                               "爻辭": {"初六": "剝床以足，蔑貞凶。",                                    "六二": "剝床以辨，蔑貞凶。", "六三": "剝之，無咎。", "六四": "剝床以膚，凶。", "六五": "貫魚，以宮人寵，無不利。", "上九": "碩果不食，君子得輿，小人剝廬。"}},
  {"id": 24, "name": "復",   "六十四卦": "地雷復",   "卦辭": "亨.出入無疾，朋來無咎.反復其道，七日來復，利有攸往。",                          "爻辭": {"初九": "不遠復，無祇悔，元吉。",                                 "六二": "休復，吉。", "六三": "頻復，厲無咎。", "六四": "中行獨復。", "六五": "敦復，無悔。", "上六": "迷復，凶，有災眚.用行師，終有大敗，以其國君凶，至于十年不克征。"}},
  {"id": 25, "name": "無妄", "六十四卦": "天雷無妄", "卦辭": "元，亨，利，貞.其匪正有眚，不利有攸往。",                                      "爻辭": {"初九": "無妄，往吉。",                                          "六二": "不耕獲，不菑畬，則利有攸往。", "六三": "無妄之災，或繫之牛，行人之得，邑人之災。", "九四": "可貞，無咎。", "九五": "無妄之疾，勿藥有喜。", "上九": "無妄，行有眚，無攸利。"}},
  {"id": 26, "name": "大畜", "六十四卦": "山天大畜", "卦辭": "利貞.不家食吉，利涉大川。",                                                   "爻辭": {"初九": "有厲，利已。",                                          "九二": "輿說輻。", "九三": "良馬逐，利艱貞.曰閒輿衛，利有攸往。", "六四": "童牛之牿，元吉。", "六五": "豶豕之牙，吉。", "上九": "何天之衢，亨。"}},
  {"id": 27, "name": "頤",   "六十四卦": "山雷頤",   "卦辭": "貞吉.觀頤，自求口實。",                                                      "爻辭": {"初九": "舍爾靈龜，觀我朵頤，凶。",                                "六二": "顛頤，拂經于丘頤，征凶。", "六三": "拂頤，貞凶，十年勿用，無攸利。", "六四": "顛頤，吉.虎視眈眈，其欲逐逐，無咎。", "六五": "拂經，居貞吉，不可涉大川。", "上九": "由頤，厲吉，利涉大川。"}},
  {"id": 28, "name": "大過", "六十四卦": "澤風大過", "卦辭": "棟橈，利有攸往，亨。",                                                        "爻辭": {"初六": "藉用白茅，無咎。",                                      "九二": "枯楊生稊，老夫得其女妻，無不利。", "九三": "棟橈，凶。", "九四": "棟隆，吉，有它吝。", "九五": "枯楊生華，老婦得其士夫，無咎無譽。", "上六": "過涉滅頂，凶，無咎。"}},
  {"id": 29, "name": "坎",   "六十四卦": "坎為水",   "卦辭": "習坎，有孚，維心亨，行有尚。",                                                "爻辭": {"初六": "習坎，入于坎窞，凶。",                                   "九二": "坎有險，求小得。", "六三": "來之坎坎，險且枕，入于坎窞，勿用。", "六四": "樽酒簋貳，用缶，納約自牖，終無咎。", "九五": "坎不盈，祇既平，無咎。", "上六": "係用徽纆，置于叢棘，三歲不得，凶。"}},
  {"id": 30, "name": "離",   "六十四卦": "離為火",   "卦辭": "利貞，亨.畜牝牛，吉。",                                                      "爻辭": {"初九": "履錯然，學之無咎。",                                     "六二": "黃離，元吉。", "九三": "日昃之離，不鼓缶而歌，則大耋之嗟，凶。", "九四": "突如其來如，焚如，死如，棄如。", "六五": "出涕沱若，戚嗟若，吉。", "上九": "王用出征，有嘉折首，獲匪其醜，無咎。"}},
  {"id": 31, "name": "咸",   "六十四卦": "澤山咸",   "卦辭": "亨，利貞，取女吉。",                                                         "爻辭": {"初六": "咸其拇。",                                              "六二": "咸其腓，凶，居吉。", "九三": "咸其股，執其隨，往吝。", "九四": "貞吉，悔亡.憧憧往來，朋從爾思。", "九五": "咸其脢，無悔。", "上六": "咸其輔頰舌。"}},
  {"id": 32, "name": "恆",   "六十四卦": "雷風恆",   "卦辭": "亨，無咎，利貞，利有攸往。",                                                  "爻辭": {"初六": "浚恆，貞凶，無攸利。",                                   "九二": "悔亡。", "九三": "不恆其德，或承之羞，貞吝。", "九四": "田無禽。", "六五": "恆其德，貞，婦人吉，夫子凶。", "上六": "振恆，凶。"}},
  {"id": 33, "name": "遯",   "六十四卦": "天山遯",   "卦辭": "亨，小利貞。",                                                               "爻辭": {"初六": "遯尾，厲，勿用有攸往。",                                 "六二": "執之用黃牛之革，莫之勝說。", "九三": "係遯，有疾厲，畜臣妾吉。", "九四": "好遯，君子吉，小人否。", "九五": "嘉遯，貞吉。", "上九": "肥遯，無不利。"}},
  {"id": 34, "name": "大壯", "六十四卦": "雷天大壯", "卦辭": "利貞。",                                                                    "爻辭": {"初九": "壯于趾，征凶，有孚。",                                    "九二": "貞吉。", "九三": "小人用壯，君子用罔.貞厲.羝羊觸藩，羸其角。", "九四": "貞吉，悔亡.藩決不羸，壯于大輿之輹。", "六五": "喪羊于易，無悔。", "上六": "羝羊觸藩，不能退，不能遂，無攸利，艱則吉。"}},
  {"id": 35, "name": "晉",   "六十四卦": "火地晉",   "卦辭": "康侯用錫馬蕃庶，晝日三接。",                                                  "爻辭": {"初六": "晉如，摧如，貞吉.罔孚，裕無咎。",                         "六二": "晉如，愁如，貞吉.受茲介福，于其王母。", "六三": "眾允，悔亡。", "九四": "晉如，鼫鼠，貞厲。", "六五": "悔亡，失得勿恤，往吉，無不利。", "上九": "晉其角，維用伐邑，厲吉無咎，貞吝。"}},
  {"id": 36, "name": "明夷", "六十四卦": "地火明夷", "卦辭": "利艱貞。",                                                                   "爻辭": {"初九": "明夷于飛，垂其翼.君子于行，三日 not 食.有攸往，主人有言。", "六二": "明夷，夷于左股，用拯救馬壯，吉。", "九三": "明夷于南狩，得其大首，不可疾貞。", "六四": "入于左腹，獲明夷之心，于出門庭。", "六五": "箕子之明夷，利貞。", "上六": "不明晦，初登于天，後入于地。"}},
  {"id": 37, "name": "家人", "六十四卦": "風火家人", "卦辭": "利女貞。",                                                                   "爻辭": {"初九": "閑有家，悔亡。",                                         "六二": "無攸遂，在中饋，貞吉。", "九三": "家人嗃嗃，悔厲吉.婦子嘻嘻，終吝。", "六四": "富家，大吉。", "九五": "王假有家，勿恤吉。", "上九": "有孚威如，終吉。"}},
  {"id": 38, "name": "睽",   "六十四卦": "火澤睽",   "卦辭": "小事吉。",                                                                  "爻辭": {"初九": "悔亡.喪馬勿逐，自復.見惡人，無咎。",                       "九二": "遇主于巷，無咎。", "六三": "見輿曳，其牛掣，其人天且劓.無初有終。", "九四": "睽孤，遇元夫，交孚，厲無咎。", "六五": "悔亡，厥宗噬膚，往何咎。", "上九": "睽孤，見豕負塗，载鬼一車，先張之弧，後說之弧，匪寇婚媾，往遇雨則吉。"}},
  {"id": 39, "name": "蹇",   "六十四卦": "水山蹇",   "卦辭": "利西南，不利東北.利見大人，貞吉。",                                           "爻辭": {"初六": "往蹇，來譽。",                                           "六二": "王臣蹇蹇，匪躬之故。", "九三": "往蹇，來反。", "六四": "往蹇，來連。", "九五": "大蹇，朋來。", "上六": "往蹇，來碩，吉，利見大人。"}},
  {"id": 40, "name": "解",   "六十四卦": "雷水解",   "卦辭": "利西南.無所往，其來復吉.有攸往，夙吉。",                                       "爻辭": {"初六": "無咎。",                                                "九二": "田獲三狐，得黃矢，貞吉。", "六三": "負且乘，致寇至，貞吝。", "九四": "解而拇，朋至斯孚。", "六五": "君子維有解，吉，有孚于小人。", "上六": "公用射隼于高墉之上，獲之，無不利。"}},
  {"id": 41, "name": "損",   "六十四卦": "山澤損",   "卦辭": "有孚，元吉，無咎，可貞，利有攸往.曷之用，二簋可用享。",                         "爻辭": {"初九": "已事遄往，無咎，酌損之。",                                "九二": "利貞，征凶.弗損益之。", "六三": "三人行則損一人，一人行則得其友。", "六四": "損其疾，使遄有喜，無咎。", "六五": "或益之，十朋之龜，弗克違，元吉。", "上九": "弗損益之，無咎，貞吉，利有攸往，得臣無家。"}},
  {"id": 42, "name": "益",   "六十四卦": "風雷益",   "卦辭": "利有攸往，利涉大川。",                                                      "爻辭": {"初九": "利用為大作，元吉，無咎。",                                 "六二": "或益之，十朋之龜，弗克違，永貞吉.王用享于帝，吉。", "六三": "益之用凶事，無咎.有孚中行，告公用圭。", "六四": "中行，告公從，利用為依遷國。", "九五": "有孚惠心，勿問元吉.有孚惠我德。", "上九": "莫益之，或擊之，立心勿恆，凶。"}},
  {"id": 43, "name": "夬",   "六十四卦": "澤天夬",   "卦辭": "揚于王庭，孚號，有厲.告自邑，不利即戎.利有攸往。",                             "爻辭": {"初九": "壯于前趾，往不勝，為咎。",                                "九二": "惕號，莫夜有戎，勿恤。", "九三": "壯于頄，有凶.君子夬夬，獨行遇雨，若濡有慍，無咎。", "九四": "臀無膚，其行次且.牽羊悔亡，聞言不信。", "九五": "莧陸夬夬，中行無咎。", "上六": "無號，終有凶。"}},
  {"id": 44, "name": "姤",   "六十四卦": "天風姤",   "卦辭": "女壯，勿用取女。",                                                          "爻辭": {"初六": "繫于金柅，貞吉.有攸往，見凶，羸豕孚蹢躅。",                 "九二": "包有魚，無咎，不利賓。", "九三": "臀無膚，其行次且，厲無大咎。", "九四": "包無魚，起凶。", "九五": "以杞包瓜，含章，有隕自天。", "上九": "姤其角，吝，無咎。"}},
  {"id": 45, "name": "萃",   "六十四卦": "澤地萃",   "卦辭": "亨.王假有廟，利見大人，亨，利貞.用大牲吉，利有攸往。",                          "爻辭": {"初六": "有孚不終，乃亂乃萃.若號，一握為笑，勿恤，往無咎。",         "六二": "引吉，無咎.孚乃利用禴。", "六三": "萃如，嗟如，無攸利.往無咎，小吝。", "九四": "大吉，無咎。", "九五": "萃有位，元永貞，悔亡。", "上六": "齎咨涕洟，無咎。"}},
  {"id": 46, "name": "升",   "六十四卦": "地風升",   "卦辭": "元亨，用見大人，勿恤.南征吉。",                                              "爻辭": {"初六": "允升，大吉。",                                            "九二": "孚乃利用禴，無咎。", "九三": "升虛邑。", "六四": "王用亨于岐山，吉無咎。", "六五": "貞吉，升階。", "上六": "冥升，利于不息之貞。"}},
  {"id": 47, "name": "困",   "六十四卦": "澤水困",   "卦辭": "亨，貞，大人吉，無咎.有言不信。",                                            "爻辭": {"初六": "臀困于株木，入于幽谷，三歲不覿。",                          "九二": "困于酒食，朱紱方來，利用享祀.征凶，無咎。", "六三": "困于石，據于蒺藜，入于其宮，不見其妻，凶。", "九四": "來徐徐，困于金車，吝，有終。", "九五": "劓刖，困于赤紱，乃徐有說，利用祭祀。", "上六": "困于葛藟，于臲卼，曰動悔，有悔，征吉。"}},
  {"id": 48, "name": "井",   "六十四卦": "水風井",   "卦辭": "改邑不改井，無喪無得，往來井井.汔至，亦未繘井，羸其瓶，凶。",                   "爻辭": {"初六": "井泥不食，舊井無禽。",                                    "九二": "井谷射鮒，甕敝漏。", "九三": "井渫不食，為我心惻，可用汲.王明，並受其福。", "六四": "井甃，無咎。", "九五": "井冽，寒泉食。", "上六": "井收勿幕，有孚元吉。"}},
  {"id": 49, "name": "革",   "六十四卦": "澤火革",   "卦辭": "已日乃孚，元亨，利貞，悔亡。",                                               "爻辭": {"初九": "鞏用黃牛之革。",                                          "六二": "已日乃革之，征吉，無咎。", "九三": "征凶，貞厲.革言三就，有孚。", "九四": "悔亡，有孚改命，吉。", "九五": "大人虎變，未占有孚。", "上六": "君子豹變，小人革面，征凶，居貞吉。"}},
  {"id": 50, "name": "鼎",   "六十四卦": "火風鼎",   "卦辭": "元吉，亨。",                                                               "爻辭": {"初六": "鼎顛趾，利出否，得妾以其子，無咎。",                        "九二": "鼎有實，我仇有疾，不我能即，吉。", "九三": "鼎耳革，其行塞，雉膏不食，方雨虧悔，終吉。", "九四": "鼎折足，覆公餗，其形渥，凶。", "六五": "鼎耳金鉉，利貞。", "上九": "鼎玉鉉，大吉，無不利。"}},
  {"id": 51, "name": "震",   "六十四卦": "震為雷",   "卦辭": "亨.震來虩虩，笑言啞啞.震驚百里，不喪匕鬯。",                                  "爻辭": {"初九": "震來虩虩，後笑言啞啞，吉。",                               "六二": "震來厲，億喪貝，躋于九陵，勿逐，七日得。", "六三": "震蘇蘇，震行无眚。", "九四": "震遂泥。", "六五": "震往來厲，億無喪，有事。", "上六": "震索索，視矍矍，征凶.震不于其躬，于其鄰，無咎.婚媾有言。"}},
  {"id": 52, "name": "艮",   "六十四卦": "艮為山",   "卦辭": "艮其背，不獲其身，行其庭，不見其人，無咎。",                                  "爻辭": {"初六": "艮其趾，無咎，利永貞。",                                   "六二": "艮其腓，不拯其隨，其心不快。", "九三": "艮其限，列其夤，厲薰心。", "六四": "艮其身，無咎。", "六五": "艮其輔，言有序，悔亡。", "上九": "敦艮，吉。"}},
  {"id": 53, "name": "漸",   "六十四卦": "風山漸",   "卦辭": "女歸吉，利貞。",                                                           "爻辭": {"初六": "鴻漸于干，小子厲，有言，無咎。",                            "六二": "鴻漸于磐，飲食衎衎，吉。", "九三": "鴻漸于陸，夫征不復，婦孕不育，凶.利禦寇。", "六四": "鴻漸于木，或得其桷，無咎。", "九五": "鴻漸于陵，婦三歲不孕，終莫之勝，吉。", "上九": "鴻漸于陸，其羽可用為儀，吉。"}},
  {"id": 54, "name": "歸妹", "六十四卦": "雷澤歸妹", "卦辭": "征凶，無攸利。",                                                            "爻辭": {"初九": "歸妹以娣，跛能履，征吉。",                                 "九二": "眇能視，利幽人之貞。", "六三": "歸妹以須，反歸以娣。", "九四": "歸妹愆期，遲歸有時。", "六五": "帝乙歸妹，其君之袂，不如其娣之袂良，月幾望，吉。", "上六": "女承筐無實，士羊無血，無攸利。"}},
  {"id": 55, "name": "豐",   "六十四卦": "雷火豐",   "卦辭": "亨，王假之，勿憂，宜日中。",                                                 "爻辭": {"初九": "遇其配主，雖旬無咎，往有尚。",                             "六二": "豐其蔀，日中見斗，往得疑疾.有孚發若，吉。", "九三": "豐其沛，日中見沬，折其右肱，無咎。", "九四": "豐其蔀，日中見斗，遇其夷主，吉。", "六五": "來章，有慶譽，吉。", "上六": "豐其屋，蔀其家，闚其戶，闃其無人，三歲不覿，凶。"}},
  {"id": 56, "name": "旅",   "六十四卦": "火山旅",   "卦辭": "小亨，旅貞吉。",                                                            "爻辭": {"初六": "旅瑣瑣，斯其所取災。",                                    "六二": "旅即次，懷其資，得童僕貞。", "九三": "旅焚其次，喪其童僕，貞厲。", "九四": "旅于處，得其資斧，我心不快。", "六五": "射雉，一矢亡，終以譽命。", "上九": "鳥焚其巢，旅人先笑後號啕.喪牛于易，凶。"}},
  {"id": 57, "name": "巽",   "六十四卦": "巽為風",   "卦辭": "小亨，利攸往，利見大人。",                                                   "爻辭": {"初六": "進退，利武人之貞。",                                      "九二": "巽在牀下，用史巫紛若，吉無咎。", "九三": "頻巽，吝。", "六四": "悔亡，田獲三品。", "九五": "貞吉，悔亡，無不利.無初有終，先庚三日，後庚三日，吉。", "上九": "巽在牀下，喪其資斧，貞凶。"}},
  {"id": 58, "name": "兌",   "六十四卦": "兌為澤",   "卦辭": "亨，利貞。",                                                                "爻辭": {"初九": "和兌，吉。",                                             "九二": "孚兌，吉，悔亡。", "六三": "來兌，凶。", "九四": "商兌，未寧，介疾有喜。", "九五": "孚于剝，有厲。", "上六": "引兌。"}},
  {"id": 59, "name": "渙",   "六十四卦": "風水渙",   "卦辭": "亨.王假有廟，利涉大川，利貞。",                                              "爻辭": {"初六": "用拯救馬壯，吉。",                                        "九二": "渙奔其机，悔亡。", "六三": "渙其躬，無悔。", "六四": "渙其群，元吉.渙有丘，匪夷所思。", "九五": "渙汗其大號，渙王居，無咎。", "上九": "渙其血，去逖出，無咎。"}},
  {"id": 60, "name": "節",   "六十四卦": "水澤節",   "卦辭": "亨.苦節，不可貞。",                                                         "爻辭": {"初九": "不出戶庭，無咎。",                                        "九二": "不出門庭，凶。", "六三": "不節之嗟，無咎。", "六四": "安節，亨。", "九五": "甘節，吉，往有尚。", "上六": "苦節，貞凶，悔亡。"}},
  {"id": 61, "name": "中孚", "六十四卦": "風澤中孚", "卦辭": "豚魚吉，利涉大川，利貞。",                                                   "爻辭": {"初九": "虞吉，有它不燕。",                                        "九二": "鳴鶴在陰，其子和之.我有好爵，吾與爾靡之。", "六三": "得敵，或鼓或罷，或泣或歌。", "六四": "月幾望，馬匹亡，無咎。", "九五": "有孚攣如，無咎。", "上九": "翰音登于天，貞凶。"}},
  {"id": 62, "name": "小過", "六十四卦": "雷山小過", "卦辭": "亨，利貞.可小事，不可大事.飛鳥遺之音，不宜上，宜下，大吉。",                    "爻辭": {"初六": "飛鳥以凶。",                                             "六二": "過其祖，遇其妣；不及其君，遇其臣；無咎。", "九三": "弗過防之，從或戕之，凶。", "九四": "無咎，弗過遇之.往厲必戒，勿用永貞。", "六五": "密雲不雨，自我西郊.公弋取彼在穴。", "上六": "弗遇過之，飞鳥離之，凶，是謂災眚。"}},
  {"id": 63, "name": "既濟", "六十四卦": "水火既濟", "卦辭": "亨，小利貞，初吉終亂。",                                                     "爻辭": {"初九": "曳其輪，濡其尾，無咎。",                                  "六二": "婦喪其茀，勿逐，七日得。", "九三": "高宗伐鬼方，三年克之，小人勿用。", "六四": "繻有衣袽，終日戒。", "九五": "東鄰殺牛，不如西鄰之禴祭，實受其福。", "上六": "濡其首，厲。"}},
  {"id": 64, "name": "未濟", "六十四卦": "火水未濟", "卦辭": "亨.小狐汔濟，濡其尾，無攸利。",                                              "爻辭": {"初六": "濡其尾，吝。",                                            "九二": "曳其輪，貞吉。", "六三": "未濟，征凶，利涉大川。", "九四": "貞吉，悔亡.震用伐鬼方，三年有賞于大國。", "六五": "貞吉，無悔.君子之光，有孚，吉。", "上九": "有孚于飲酒，無咎.濡其首，有孚失是。"}}
]

