def to_爻名(index, 陰陽):
    indices_cn = ['初', '二', '三', '四', '五', '上']
    a = indices_cn[index-1]
    yy = '九' if 陰陽 == '陽' else '六'
    if index == 1 or index == 6:
        return a + yy # index position switched 
    else:
        return yy + a


def print花(卦):
    for i in range(6,0,-1):
        print(f"{i}爻: {卦[i-1]} {'---' if 卦[i-1][1] == '陽' else '- -'}") 


def print卦(全卦, 变爻_index):
    原卦 = [y[0] for y in 全卦 ]
    变卦 = [y[1] for y in 全卦 ]
    四象 = [y[2] for y in 全卦 ]
    变爻_len = len(变爻_index)

    print(f"变爻: {变爻_index} 变爻数量: {变爻_len}")
    for i in range(6,0,-1):
        print(str(全卦[i-1]))

    # len == 0, 原卦 卦辭
    # len == 1, 原卦 max(爻辭)
    # len == 2, 原卦 max(爻辭)
    # len == 3, 原卦 卦辭 + 变卦 卦辭
    # len == 4, 变卦 min(爻辭)
    # len == 5, 变卦 min(爻辭)
    # len == 6, 变卦 卦辭, if 乾 then X, if 坤 then Y

    def print_detail(卦, show_卦辭=False, 变爻_index=[]):
        上三爻 = ''.join(卦[3:6])
        下三爻 = ''.join(卦[0:3])
        print(f"上三爻:{上三爻} \t 下三爻:{下三爻}")
        上卦 = 三爻_to_八卦[上三爻]
        下卦 = 三爻_to_八卦[下三爻]
        print(f"上卦:{上卦}")
        print(f"下卦:{下卦}")
        卦64_name = 八卦_to_六十四卦[(上卦,下卦)]
        ID = 六十四卦_to_id[卦64_name]
        卦辭 = 六十四卦_to_卦辭[卦64_name]
        爻辭 = 六十四卦_to_爻辭[卦64_name]

        print(f"六十四卦[第{ID}卦]:{卦64_name}", end="")

        # TODO if 乾 then X, if 坤 then Y
        if len(变爻_index) in [0,6]:
            if 卦64_name == "乾為天":
                print("\t [用九]", end="")
                变爻_index = []
                show_卦辭 = True

            if 卦64_name == "坤为地":
                print("\t [用六]", end="")
                变爻_index = []
                show_卦辭 = True

        print(f"\t 卦辭:{卦辭}", end="")
        if len(变爻_index) in [0,6]:
            print(f"<<<<<<<<<<<<<<<<<<<", end= "")
        print()

        for i in range( 6, 0, -1):
            陰陽 = 卦[i-1]
            flag = '*' if 四象[i-1][0] == '老' else ' '
            line = '---' if 陰陽 == '陽' else '- -'
            爻名 = to_爻名(i, 陰陽)
            print(f"{flag}{i}爻: {爻名} ({四象[i-1]}) {line} \t 爻辭: {爻辭[爻名]}", end="")
            if i in 变爻_index:
                print(f"<<<<<<<<<<<<<<<<<<<")
            else:
                print()

    if 变爻_len <= 3:
        print(f"---------------------- 原卦: -----------------------")
        print(f"原卦: {原卦}")
        show_爻辭 = [max(变爻_index)] if 变爻_len in [1,2] else []
        show_卦辭 = len(变爻_index) in [0,6]
        print_detail(原卦, show_卦辭, show_爻辭)
    
    if 变爻_len >= 3:
        print(f"---------------------- 变卦: -----------------------")
        print(f"变卦: {变卦}")
        show_爻辭 = [min(变爻_index)] if 变爻_len in [4,5] else []
        show_卦辭 = len(变爻_index) in [0,6]
        print_detail(变卦, show_卦辭, show_爻辭)



