def main(花, Question):
    变爻_index = [i+1 for i, y in enumerate(花) if y == 0 or y == 3]  # '变爻' index
    print(f"-================================ 花: {花} ================================-")
    print(f"1个花 = 少陽 (Shao Yang) = 陽爻 --- 静爻 (不变)")
    print(f"2个花 = 少陰 (Shao Yin) = 陰爻 - - 静爻 (不变)")
    print(f"0个花 = 老陽 (Lao Yang) = 陽爻 --- 动爻 (会变陰)")
    print(f"3个花 = 老陰 (Lao Yin) = 陰爻 - - 动爻 (会变陽)")

    print("reply in chinese,", Question)
    四象 = [花_to_全卦[y] for y in 花 ]
    print卦(四象, 变爻_index)
    print(f"-===============================================================================-")


